package com.arkeomag.pro; import android.content.*;import android.view.*;import android.graphics.*;
public class BarGraphView extends View{Paint p=new Paint(1);float x,y,z; public BarGraphView(Context c){super(c);} public void set(float a,float b,float cc){x=a;y=b;z=cc;invalidate();} protected void onDraw(Canvas c){int w=getWidth(),h=getHeight();p.setColor(Color.rgb(12,22,38));c.drawRoundRect(0,0,w,h,24,24,p);float[] v={Math.abs(x),Math.abs(y),Math.abs(z)};String[] s={"X","Y","Z"};for(int i=0;i<3;i++){float bw=w/5f;float left=w*(i+.7f)/3f-bw/2;float bh=Math.min(h-50,v[i]*4);p.setColor(Palette.color(v[i]/50f));c.drawRoundRect(left,h-28-bh,left+bw,h-28,18,18,p);p.setColor(Color.WHITE);p.setTextSize(24);p.setTextAlign(Paint.Align.CENTER);c.drawText(s[i],left+bw/2,h-5,p);}}}
